mapper.sql:
SELECT COUNT(1) OVER() AS TOTAL_CNT , COUNT(1) OVER() - ROW_NUMBER() OVER(ORDER BY A.ACTV_DTTM DESC) + 1 AS LINE_NO , A.USER_ACTV_ID , A.USER_ID , A.SBJCT_ID , A.REQ_TYCD , A.USER_REQ_URL , A.USER_REQ_MENU , A.USER_REQ_CTS , A.USER_TYCD , A.CNTN_IP , A.CNTN_DVC_TYCD , A.CNTN_BRWSR , A.ACTV_DTTM , A.SESS_ID , A.SESS_SDTTM , A.SESS_EDTTM , A.RGTR_ID , A.REG_DTTM FROM TB_LMS_LOG_USER_ACTV A WHERE 1=1
AND A.SBJCT_ID = #{sbjctId}
AND A.USER_ID = #{userId}
AND A.ACTV_DTTM >= #{searchFrom}
AND A.ACTV_DTTM <= #{searchTo}
